var days=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"],months=["Jan","Feb","Mar","Apr","May","June","July","Aug","Sept","Oct","Nov","Dec"],delay=1e3;function initializeTimestamp(){var a=new Date,b=days[a.getDay()],c=a.getDate(),d=months[a.getMonth()],e=a.toLocaleTimeString("en-us",{hour12:!1});return b.concat(" ",d," ",c," ",e)}function currentTimestamp(){var a=new Date;return a.toLocaleTimeString("en-us",{hour12:!1})}function updateTimestamp(){document.querySelector("#menutime").textContent=currentTimestamp()}function randomInt(a,b){var c=Math.ceil(a),d=Math.floor(b);return Math.floor(Math.random()*(d-c+1)+c)}export function initTimestamp(){setInterval(updateTimestamp,delay),updateTimestamp(),document.getElementById("timestamp").innerHTML="Last login: ".concat(initializeTimestamp()," on ttys00",randomInt(0,6))}